// lib/data/songs_data.dart

class Song {
  final String title;
  final String artist;
  final String lyrics;
  final String category;
  final String emoji;

  const Song({
    required this.title,
    required this.artist,
    required this.lyrics,
    required this.category,
    required this.emoji,
  });
}

